// Auth: cron has no headers, treat as system-authenticated. Webhook requires bearer token + admin role.
const isCron = !$input.item.json.headers;
if (isCron) return { json: { _ok: true, source: 'cron' } };
const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token, source: 'webhook' } };

const src = $('Extract Auth').first().json.source;
if (src === 'cron') return { json: { _ok: true } };
const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
return { json: { _ok: true } };

const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const carriers = allOf('Fetch Carriers');
const submissions = allOf('Fetch Submissions 90d');
const now = Date.now();

// Status counts
const counts = { not_applied: 0, pending: 0, approved: 0, active: 0, suspended: 0, terminated: 0 };
carriers.forEach(function (c) { counts[c.appointment_status] = (counts[c.appointment_status] || 0) + 1; });

// Stale pending — applied >30 days ago, still pending
const stalePending = carriers.filter(function (c) {
  if (c.appointment_status !== 'pending') return false;
  if (!c.appointment_applied_at) return false;
  const days = (now - new Date(c.appointment_applied_at).getTime()) / 86400000;
  return days > 30;
});

// Submissions per carrier (90d)
const submissionsByCarrier = {};
const premiumsByCarrier = {};
submissions.forEach(function (s) {
  if (!s.carrier_id) return;
  submissionsByCarrier[s.carrier_id] = (submissionsByCarrier[s.carrier_id] || 0) + 1;
  premiumsByCarrier[s.carrier_id] = (premiumsByCarrier[s.carrier_id] || 0) + (parseInt(s.annual_premium_cents) || 0);
});

// Enrich carriers with activity
const enriched = carriers.map(function (c) {
  return Object.assign({}, c, {
    submissions_90d: submissionsByCarrier[c.id] || 0,
    premium_volume_90d_cents: premiumsByCarrier[c.id] || 0
  });
});

return { json: {
  ok: true,
  generated_at: new Date().toISOString(),
  counts: counts,
  total_carriers: carriers.length,
  active_count: counts.active,
  pending_count: counts.pending,
  stale_pending_count: stalePending.length,
  stale_pending: stalePending.map(function (c) { return { id: c.id, carrier_name: c.carrier_name, applied_at: c.appointment_applied_at }; }),
  carriers: enriched
} };
